import{_ as a,o as n,c as t,S as o}from"./chunks/framework.DZlzLDBr.js";const g=JSON.parse('{"title":"Syncing","description":"","frontmatter":{},"headers":[],"relativePath":"Syncing.md","filePath":"Syncing.md","lastUpdated":null}'),r={name:"Syncing.md"};function s(i,e,d,c,l,h){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="syncing" tabindex="-1">Syncing <a class="header-anchor" href="#syncing" aria-label="Permalink to &quot;Syncing&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Syncing updates Sprout&#39;s card database from your Markdown notes.</p><p>After creating, editing, or deleting card blocks, sync so changes take effect in your card database.</p><h2 id="how-to-sync" tabindex="-1">How to sync <a class="header-anchor" href="#how-to-sync" aria-label="Permalink to &quot;How to sync&quot;">​</a></h2><ul><li><strong>Header button:</strong> click the Sprout sync button in any view when Sprout is open.</li><li><strong>Manual command:</strong> run <strong>Sprout: Sync cards</strong> from the command palette.</li><li><strong>Automatic sync:</strong> runs when editing cards in <a href="./Card-Browser">Card Browser</a> or edit modals.</li></ul><h2 id="what-happens-during-sync" tabindex="-1">What happens during sync <a class="header-anchor" href="#what-happens-during-sync" aria-label="Permalink to &quot;What happens during sync&quot;">​</a></h2><ol><li><strong>Scan:</strong> find card blocks in Markdown files.</li><li><strong>Parse:</strong> read fields using the configured delimiter (default <code>|</code>).</li><li><strong>Match:</strong> connect blocks with existing <code>^sprout-#########</code> anchors to stored scheduling data.</li><li><strong>Create:</strong> add new blocks that do not yet have anchors.</li><li><strong>Update:</strong> refresh stored data for changed blocks.</li><li><strong>Remove:</strong> delete cards whose source blocks were removed.</li><li><strong>Anchor:</strong> insert <code>^sprout-#########</code> above or below blocks (based on settings).</li></ol><h2 id="card-anchors" tabindex="-1">Card anchors <a class="header-anchor" href="#card-anchors" aria-label="Permalink to &quot;Card anchors&quot;">​</a></h2><p>After syncing, each card block gets an anchor line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>^sprout-#########</span></span></code></pre></div><p>This anchor links note content to scheduling data.</p><p>Do not edit or delete it. If it is removed, next sync creates a new ID and previous progress is not linked to that block.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you remove an anchor by mistake, find the card ID in <a href="./Card-Browser">Card Browser</a> and re-add the line.</p></div><h2 id="quarantined-cards" tabindex="-1">Quarantined cards <a class="header-anchor" href="#quarantined-cards" aria-label="Permalink to &quot;Quarantined cards&quot;">​</a></h2><p>If a card block has invalid syntax, Sprout quarantines it instead of deleting it.</p><p>See quarantined entries in Settings with error details, fix the note, then sync again.</p><h2 id="excluded-content" tabindex="-1">Excluded content <a class="header-anchor" href="#excluded-content" aria-label="Permalink to &quot;Excluded content&quot;">​</a></h2><ul><li><strong>Fenced code blocks:</strong> ignored by default (can be changed in Settings → Indexing).</li><li><strong>Non-Markdown files:</strong> not scanned.</li></ul>',20)])])}const p=a(r,[["render",s]]);export{g as __pageData,p as default};
